//udc팝업공통 콜백처리
scwin.f_setUdcPopCallback = function (ret, objCode, objName) {
  try {
    // 선언부
    let rtnList = new Array(); // 공통POP-UP -> 요청화면
    rtnList = ret;
    if (rtnList != null) {
      if (rtnList[0] == "N/A") {
        objCode.setValue("");
        objName.setValue("");
        objCode.hidVal = "";
        return;
      }
      objCode.setValue(rtnList[0]); // 코드값
      objName.setValue(rtnList[1]); // 코드명
      objCode.hidVal = rtnList[0]; // 코드값
    } else {
      objCode.setValue("");
      objName.setValue("");
      objCode.hidVal = "";
    }
  } catch (e) {
    console.log(e);
  }
};

