scwin.f_certiNoDetail = function (arg) {
  //if(arg != "NEW" && ds_merchantcertilist.getRowCount() < 1){
  //	$c.gus.cfAlertMsg(MSG_CM_WRN_008,["CERTI 내역"]);
  //	return;
  //}

  let condition = "?";
  var row = ds_merchantcertilist.getRowPosition();
  var pgmId = ds_merchantcertilist.getCellData(row, "pgmId");
  var v_odrNo = ds_merchantcertidtllist.getCellData(0, "odrNo").substring(0, 13);
  //var v_odrNo = ds_merchantcertidtllist.getCellData(1, "odrNo").substring(0,13);

  if (pgmId == "fs_202_06_04p.jsp") {
    pgmId = "fs_202_04_01b.jsp";
  }
  var strCertiNoDetailUrl = "/ui/ds/fs/bilg/" + pgmId.replace(".jsp", ".xml");
  //var strCertiNoDetailUrl = "/ds/fs/bilg/"+pgmId.replaceAll('.jsp','')+".xml";

  var title = "";
  //console.log("strCertiNoDetailUrl ==> "+strCertiNoDetailUrl);

  // 선택된 certiNo 정보 : bilgLodeptCd , certiNo
  var v_bilgLodeptCd = ds_merchantcertilist.getCellData(row, "bilgLodeptCd");
  var v_certiNo = ds_merchantcertilist.getCellData(row, "certiNo");
  var v_link = "true";
  var paramObj = {};
  if (pgmId == "fs_202_03_02b.jsp") {
    //condition += "odrNo="+v_odrNo+ "&flag=DETAIL";
    paramObj.odrNo = v_odrNo;
    paramObj.flag = "DETAIL";
  } else {
    //condition += "bilgLodeptCd="+v_bilgLodeptCd+"&certiNo="+v_certiNo+"&link="+v_link;
    paramObj.bilgLodeptCd = v_bilgLodeptCd;
    paramObj.certiNo = v_certiNo;
    paramObj.link = v_link;
  }
  if (pgmId == "fs_202_04_01b.jsp") {
    title = "수출입 거래명세서 작성";
  } else if (pgmId == "fs_202_04_03b.jsp") {
    title = "기간매출 거래명세서 작성";
  } else if (pgmId == "fs_202_04_06b.jsp") {
    title = "내수 거래명세서 작성";
  } else if (pgmId == "fs_202_05_01b.jsp") {
    title = "컨테이너별 CERTI 생성";
  } else if (pgmId == "fs_202_05_03b.jsp") {
    title = "CERTI 생성";
  } else if (pgmId == "fs_202_05_05b.jsp") {
    title = "기간매출 CERTI 생성";
  } else if (pgmId == "fs_202_03_02b.jsp") {
    title = "일반청구오더관리";
  }

  //console.log("팝업~~");
  //console.log(paramObj);
  $c.win.openMenu($p, title, strCertiNoDetailUrl, pgmId, paramObj, {
    openAction: "exist"
  });

  //$c.gus.cfTabMenuUpdate( strCertiNoDetailUrl+condition , title) ;
  //$c.win.openMenu(menuTitle, strOrderDetailUrl, "fs_204_02_04b.jsp", condition);
};

